import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.C9sp7nFj.js";const s="/screenshots/payslips-list.jpeg",g=JSON.parse('{"title":"View payslips","description":"","frontmatter":{},"headers":[],"relativePath":"guide/payslip.md","filePath":"guide/payslip.md","lastUpdated":1776630283000}'),n={name:"guide/payslip.md"};function l(r,e,p,h,d,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="view-payslips" tabindex="-1">View payslips <a class="header-anchor" href="#view-payslips" aria-label="Permalink to &quot;View payslips&quot;">​</a></h1><p>See your monthly payslip, inspect the breakdown, and download a PDF.</p><h2 id="open-the-payslip-list" tabindex="-1">Open the Payslip list <a class="header-anchor" href="#open-the-payslip-list" aria-label="Permalink to &quot;Open the Payslip list&quot;">​</a></h2><p>Access it from:</p><ul><li><strong>Home</strong> → <strong>Payslip</strong> (quick action tile), or</li><li><strong>More tab</strong> → <strong>Payslip</strong></li></ul><figure class="screenshot"><img src="'+s+'" alt="List of monthly payslips"><figcaption>Payslips — every posted slip with period and net pay; tap one to open the detail view and download a PDF.</figcaption></figure><h2 id="the-list" tabindex="-1">The list <a class="header-anchor" href="#the-list" aria-label="Permalink to &quot;The list&quot;">​</a></h2><p>Each row is one monthly payslip, most recent first. You see:</p><ul><li><strong>Slip name</strong> (e.g. <code>Sal Slip/None/00006</code>)</li><li><strong>Period</strong> — start date → end date (e.g. <code>1 Mar – 31 Mar</code>)</li><li><strong>Net pay</strong> in your company&#39;s currency</li></ul><p>Past slips stay in the list indefinitely — you can always open an old month.</p><h2 id="tap-a-payslip" tabindex="-1">Tap a payslip <a class="header-anchor" href="#tap-a-payslip" aria-label="Permalink to &quot;Tap a payslip&quot;">​</a></h2><p>Opens the payslip detail screen showing:</p><ul><li><strong>Net pay</strong> at the top in large text, with the currency symbol (e.g. the Saudi Riyal glyph for SAR-denominated slips)</li><li><strong>Earnings</strong> card — each component (Basic, HRA, Allowances, …) with its amount</li><li><strong>Deductions</strong> card — each deduction (if any) with its amount</li><li>Two action buttons: <strong>Download</strong> and <strong>Share</strong></li></ul><h2 id="download-the-pdf" tabindex="-1">Download the PDF <a class="header-anchor" href="#download-the-pdf" aria-label="Permalink to &quot;Download the PDF&quot;">​</a></h2><p>Tap <strong>Download</strong>.</p><p><strong>On the native Android app:</strong></p><ul><li>The PDF is saved to your phone&#39;s <strong>Documents</strong> folder</li><li>You see a confirmation: <strong>&quot;Saved to Documents.&quot;</strong></li><li>Open a file manager / Google Files app → Documents → there it is</li><li>Filename looks like <code>Sal_Slip_None_00006.pdf</code> (slashes in the original name are replaced with underscores so file systems can handle it)</li></ul><p><strong>On the web app:</strong></p><ul><li>Your browser downloads the PDF to its default Downloads folder</li><li>Some browsers open it in a new tab first — use the browser&#39;s save option from there</li></ul><p>The PDF is the full formal payslip as generated by your Frappe HR setup — same format HR prints and sends via email.</p><h2 id="share-it" tabindex="-1">Share it <a class="header-anchor" href="#share-it" aria-label="Permalink to &quot;Share it&quot;">​</a></h2><p>Tap <strong>Share</strong> to open your phone&#39;s share sheet and send the PDF directly to:</p><ul><li>WhatsApp</li><li>Email (Gmail, Outlook, …)</li><li>Google Drive / Dropbox</li><li>Any other app that accepts PDF</li></ul><p>On the web, Share falls back to Download on browsers that don&#39;t support the native share API.</p><h2 id="offline-behaviour" tabindex="-1">Offline behaviour <a class="header-anchor" href="#offline-behaviour" aria-label="Permalink to &quot;Offline behaviour&quot;">​</a></h2><ul><li><strong>The list of payslips</strong> — cached after the first time you view it; works offline</li><li><strong>A specific payslip&#39;s breakdown</strong> — only available offline if you&#39;ve opened it at least once while online</li><li><strong>The PDF</strong> — cached if you&#39;ve downloaded it before while online; any earlier downloads stay in Documents / browser Downloads regardless of network</li></ul><h2 id="if-something-s-wrong-with-the-amounts" tabindex="-1">If something&#39;s wrong with the amounts <a class="header-anchor" href="#if-something-s-wrong-with-the-amounts" aria-label="Permalink to &quot;If something&#39;s wrong with the amounts&quot;">​</a></h2><p>If you spot an incorrect figure:</p><ul><li><strong>Don&#39;t edit in the app</strong> — payslips are read-only from the mobile side</li><li>Contact HR with your payslip name (<code>HR-EXP-2026-00001</code> etc.) so they can open it on the Desk and fix</li></ul><h2 id="why-does-it-say-sal-slip-none" tabindex="-1">Why does it say &quot;Sal Slip/None/…&quot;? <a class="header-anchor" href="#why-does-it-say-sal-slip-none" aria-label="Permalink to &quot;Why does it say &quot;Sal Slip/None/…&quot;?&quot;">​</a></h2><p>That&#39;s the default Frappe naming series your HR team hasn&#39;t customised. It still works correctly — the name is just a bit awkward. HR can change the naming series in <strong>Payroll Settings → Salary Slip Naming Series</strong> on the Desk.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/expense">File an expense claim</a></li><li><a href="/guide/profile">Profile settings</a></li></ul>',33)])])}const y=a(n,[["render",l]]);export{g as __pageData,y as default};
